t le pourcentage de rongeurs parmi la population des mammifères ?\";s:11:\"explanation\";s:135:\"Ces animaux se caractérisent par leur unique paire d\'incisives qui leur servent à ronger, à creuser des galeries ou à se défendre.\";s:4:\"hint\";N;s:9:\"imageName\";N;}','superadmin@omega.com'),(5820,'create','2025-08-10 14:24:58','1001','App\\Entity\\Proposal',1,'a:3:{s:7:\"content\";s:4:\"30 %\";s:9:\"isCorrect\";b:0;s:9:\"imageName\";N;}','superadmin@omega.com'),(5821,'create','2025-08-10 14:24:58','1002','App\\Entity\\Proposal',1,'a:3:{s:7:\"content\";s:4:\"40 %\";s:9:\"isCorrect\";b:1;s:9:\"imageName\";N;}','superadmin@omega.com'),(5822,'create','2025-08-10 14:24:58','1003','App\\Entity\\Proposal',1,'a:3:{s:7:\"content\";s:4:\"20 %\";s:9:\"isCorrect\";b:0;s:9:\"imageName\";N;}','superadmin@omega.com'),(5823,'create','2025-08-10 14:24:58','1004','App\\Entity\\Proposal',1,'a:3:{s:7:\"content\";s:4:\"10 %\";s:9:\"isCorrect\";b:0;s:9:\"imageName\";N;}','superadmin@omega.com'),(5824,'update','2025-08-10 14:24:58','251','App\\Entity\\Question',2,'a:2:{s:7:\"content\";s:49:\"What is the percentage of rodents among mammals ?\";s:11:\"explanation\";s:126:\"These animals are characterized by their unique pair of incisors which serve them to gnaw, dig galleries or defend themselves.\";}','superadmin@omega.com'),(5825,'update','2025-08-10 14:24:58','1001','App\\Entity\\Proposal',2,'a:1:{s:7:\"content\";s:3:\"40%\";}','superadmin@omega.com'),(5826,'update','2025-08-10 14:24:58','1002','App\\Entity\\Proposal',2,'a:1:{s:7:\"content\";s:3:\"20%\";}','superadmin@omega.com'),(5827,'update','2025-08-10 14:24:58','1003','App\\Entity\\Proposal',2,'a:1:{s:7:\"content\";s:3:\"10%\";}','superadmin@omega.com'),(5828,'update','2025-08-10 14:24:58','1004','App\\Entity\\Proposal',2,'a:1:{s:7:\"content\";s:3:\"30%\";}','superadmin@omega.com'),(5829,'update','2025-08-10 14:24:58','251','App\\Entity\\Question',3,'a:2:{s:7:\"content\";s:56:\"Wie hoch ist der Anteil der Nagetiere bei Säugetieren 