INSERT INTO `question` VALUES (63,17,2,3,3,'Par quelle techniques les égyptiens préservaient-ils les corps pour les inhumer ?','L\'embaumement vise à conserver les corps des personnes mortes dans un état plus ou moins proche de leur état vivant.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(64,17,2,3,3,'Quelle couleur symbolisait la végétation et la régénération en Égypte ancienne ?','L\'Égypte antique est une ancienne civilisation d\'Afrique du Nord-Est concentrée le long du cours inférieur du Nil.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(65,17,2,3,3,'Comment appelle-t-on un cadavre préservé de la putréfaction au moyen de l\'embaumement ?','C\'est une dessiccation naturelle dans une grotte sépulcrale qui est à l\'origine de la plus ancienne momie attestée : la momie de Fallon.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(66,17,2,3,3,'Quel concept décrit la fascination pour la culture et l\'histoire de l\'Égypte Antique ?','Le tourisme de masse, initié en Égypte par l\'agence Cook en 1869, développe cette égyptomanie.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(67,17,2,3,3,'Comment appelle-t-on la « cuve » contenant le cercueil et la momie d\'un pharaon ?','En tant qu\'objet funéraire, le sarcophage est présent dans des cultures et civilisations diverses et éloignées les unes des autres.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(68,17,2,3,3,'Quelle était la première fonction des monumentales pyramides d\'Égypte ?','Tombeaux des rois et des reines, la forme pyramidale de pierre accueille une ou plusieurs chambres internes reliées par des couloirs.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(69,17,2,3,3,'Quel film de 1999 a pour personnage principal la momie d\'un prêtre égyptien maudit ?','Le film a donné lieu à deux suites : « Le Retour de la momie » en 2001 puis « La Momie : La Tombe de l\'empereur Dragon » en 2008.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(70,17,2,3,3,'Près de quelle ville importante sont situées les grandes pyramides d\'Égypte ?','Le centre historique de la ville comprend le Vieux Caire ainsi que le quartier islamique, classé au patrimoine mondial de l\'humanité.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL),(71,17,2,3,3,'Quels films et série dérivée de ce film mêlent science-fiction et mythologie égyptienne ?','Contrairement à la plupart des films basés sur l\'exploration de la galaxie, l\'action de « Stargate » se situe à notre époque.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(72,17,2,3,3,'Combien y a-t-il de grandes pyramides sur le plateau de Gizeh, classé à l\'UNESCO ?','Les trois plus grandes pyramides d\'Égypte (Khéops, Khéphren et Mykérinos) se situent sur la nécropole de Gizeh.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(73,17,3,3,3,'Quelle partie du visage manque-t-il au Sphinx devant les grandes pyramides de Gizeh ?','Le corps du sphinx, sculpté dans la couche sous-jacente de calcaire plus tendre, pourrait être celui d\'un lion couché.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(74,17,3,3,3,'Quel grand pharaon fit construire une capitale « de loisir », laissant l\'administratif à Thèbes ?','Son règne d\'une exceptionnelle durée pour l\'époque couvre à lui seul la moitié du nombre d\'années que comprend la XIXe dynastie.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(75,17,3,3,3,'Quel opéra de Verdi met en scène une intrigue entre une esclave et un officier égyptien ?','N\'ayant pas assisté à la première, Verdi ne fut pas satisfait par ce succès parce que la salle n\'était composée que de dignitaires invités.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(76,17,3,3,3,'Combien mesurent les colosses de Ramsès II à l\'entrée du grand temple d\'Abou Simbel ?','Le temple est taillé dans le grès de la roche pour sa majeure partie, dont la façade composée de quatre statues colossales de Ramsès II.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(77,17,3,3,3,'Dans quel musée est conservée la pierre de Rosette désormais liée aux hiéroglyphes ?','L\'inscription qu\'elle comporte est un décret promulgué à Memphis par le pharaon Ptolémée V en 196 av. J.-C.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(78,17,3,3,3,'Qui est le Dieu seigneur de la Nécropole, de la mort et protecteur des embaumeurs ?','Les principales épithètes du dieu Anubis mettent en avant ses liens avec les nécropoles du pays et son rôle de divinité funéraire.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(79,17,3,3,3,'Quel pharaon de la dynastie des ramessides est associé à l\'Âge d\'Or de l\'Égypte ?','À l\'instar d\'autres personnages historiques, Ramsès II est réputé pour être un grand guerrier et conquérant.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(80,17,3,3,3,'En investissant la Vallée des Rois, qui les égyptiens voulaient-ils éloigner ?','« Les Pilleurs de sarcophages » est un roman historique écrit par Odile Weulersse paru en 1984, édité par Hachette Jeunesse.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(81,17,3,3,3,'À la hauteur de quelle grande ville se situe la vallée des rois, connue des égyptologues ?','La vallée des rois est connue pour abriter les hypogées de nombreux pharaons, d\'épouses et d\'enfants de pharaons.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(82,17,3,3,3,'Qui envoya Sekhmet massacrer les humains qui complotaient avant de se repentir ?','Déesse guerrière personnifiant la puissance destructrice du Soleil, Sekhmet est l\'instrument de la vengeance de Rê.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(83,17,4,3,3,'Quel instrument de la famille des percussions était courant dans l\'Égypte ancienne ?','Le sistre est constitué d\'un cadre dans lequel sont enfilées des coques de fruits, des coquilles ou des rondelles métalliques.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(84,17,4,3,3,'Quelle déesse égyptienne aux traits félins est le symbole de la maternité et de la fécondité ?','Bastet est l\'une des déesses les plus discrètes du panthéon égyptien, et n\'est jamais représentée, sinon dans son temple à Bubastis.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(85,17,4,3,3,'À quel endroit de l\'Égypte ancienne pouvait-on trouver la région du Fayoum ?','Le Fayoum proprement dit est une oasis du désert de Libye, sa frontière orientale étant environ à 30 kilomètres à l\'ouest du Nil.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(86,17,4,3,3,'Quel est le nom grec de la double couronne égyptienne portée par les pharaons ?','Le nom égyptien de cette double couronne est skhemty, qui deviendra « pschent », « les deux puissants ».',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(87,17,4,3,3,'Quel pharaon tenta d\'instaurer une religion à Dieu unique en changeant son nom ?','On ne sait ni quand ni comment Akhenaton décède, ses successeurs ayant tout fait pour effacer les traces du roi hérétique.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(88,17,4,3,3,'Au nombre de quatre, que recueillent les vases canopes lors de l\'embaumement d\'un corps ?','Les vases canopes étaient fabriqués en calcaire, en albâtre, en terre cuite ou en céramique et étaient déposés près du sarcophage.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(89,17,4,3,3,'Quel site mégalithique égyptien est antérieur de 1000 ans à celui de Stonehenge ?','Ce site, bien conservé par les conditions désertiques du climat, offre un grand intérêt pour l\'anthropologie, l\'archéologie et la préhistoire.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(90,17,4,3,3,'Quel animal incarne la représentation du Dieu Apophis, personnification du chaos ?','Dans certaines scènes, le roi ou le pharaon lors de la bataille est représenté avec un objet rond qui symbolise l\'oeil d\'Apophis.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(91,17,4,3,3,'Sous l\'influence d\'Akhenaton, quel art bouleversa les canons artistiques de l\'époque ?','Il se caractérise par un art délicat où abondent les plantes, les fleurs et les oiseaux et par la représentation réaliste des personnages.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(92,17,4,3,3,'Quelle reine usurpa le titre de Pharaon en attendant que Toutmôsis III puisse régner ?','Selon James Henry Breasted, Hatchepsout est connue pour être la « première grande femme dont l\'histoire ait gardé le nom ».',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL),(93,18,3,3,3,'Quelle ville française était appelée la cité des papes au Moyen Âge ?','Avignon est l\'une des rares villes françaises à avoir conservé ses remparts et son centre historique, composé du palais des papes.',NULL,NULL,'2025-08-10 14:23:29','2025-08-10 14:23:29',NULL),(94,18,3,3,3,'Quel diplomate français a succédé au Cardinal de Richelieu ?','Le cardinal choisit comme pièce principale de son blason le faisceau de licteur, un signe de romanité.',NULL,NULL,'2025-08-10 14:23:29','2025-08-10 14:23:29',NULL),(95,18,3,3,3,'Quelle reine de France a porté le chapeau dans l\'affaire du collier ?','Les joailliers Boehmer et Bassenge réclamèrent à la reine 1,6 million de livres pour l\'achat d\'un collier de diamants.',NULL,NULL,'2025-08-10 14:23:29','2025-08-10 14:23:29',NULL),(96,18,3,3,3,'Quand François Mitterrand fut-il élu président de la France pour la première fois ?','Mitterrand sera élu 21e président de la République française face à Valéry Giscard d\'Estaing avec 51 % des suffrages exprimés.',NULL,NULL,'2025-08-10 14:23:29','2025-08-10 14:23:29',NULL),(97,18,3,3,3,'Quelle ville Jeanne d\'Arc a-t-elle héroïquement libérée des Anglais ?','Jeanne d\'Arc a été condamnée à être brûlée vive en 1431 après un procès en hérésie conduit par Pierre Cauchon.',NULL,NULL,'2025-08-10 14:23:29','2025-08-10 